const { app } = require('@azure/functions');
const { CosmosClient } = require('@azure/cosmos');

const cosmosClient = new CosmosClient(process.env.COSMOS_CONNECTION_STRING);
const database = cosmosClient.database(process.env.COSMOS_DATABASE_ID);
const container = database.container(process.env.COSMOS_CONTAINER_ID);

app.http('batchDataProcessor', {
    methods: ['POST', 'GET'],
    authLevel: 'function',
    timeout: '00:10:00',
    handler: async (request, context) => {
        const startTime = Date.now();
        const maxExecutionTime = 590000;
        
        context.log('Starting batch data processing...');
        
        let processedCount = 0;
        let errorCount = 0;
        let continuationToken = null;
        const batchSize = 100;
        const results = [];
        
        try {
            const requestBody = await request.text();
            let config = {};
            
            try {
                config = requestBody ? JSON.parse(requestBody) : {};
            } catch (e) {
                config = {};
            }
            
            const querySpec = config.query || {
                query: "SELECT * FROM c"
            };
            
            const maxItems = config.maxItems || 10000;
            const processingFunction = config.processingType || 'default';
            
            do {
                const elapsedTime = Date.now() - startTime;
                if (elapsedTime > maxExecutionTime) {
                    context.log(`Approaching timeout limit. Processed ${processedCount} items so far.`);
                    break;
                }
                
                const queryOptions = {
                    maxItemCount: batchSize,
                    continuationToken: continuationToken
                };
                
                const { resources, continuationToken: newToken, requestCharge } = await container.items
                    .query(querySpec, queryOptions)
                    .fetchNext();
                
                continuationToken = newToken;
                
                context.log(`Fetched ${resources.length} items. Request charge: ${requestCharge} RUs`);
                
                for (const item of resources) {
                    try {
                        const processedItem = await processItem(item, processingFunction, context);
                        results.push(processedItem);
                        processedCount++;
                        
                        if (processedCount >= maxItems) {
                            context.log(`Reached maximum items limit: ${maxItems}`);
                            continuationToken = null;
                            break;
                        }
                        
                        if (processedCount % 100 === 0) {
                            context.log(`Progress: ${processedCount} items processed`);
                        }
                    } catch (error) {
                        errorCount++;
                        context.log(`Error processing item ${item.id}: ${error.message}`);
                    }
                }
                
                if (continuationToken && resources.length === 0) {
                    break;
                }
                
            } while (continuationToken);
            
            const executionTime = Date.now() - startTime;
            
            const summary = {
                status: 'completed',
                processedCount: processedCount,
                errorCount: errorCount,
                executionTimeMs: executionTime,
                executionTimeSec: Math.round(executionTime / 1000),
                hasMoreData: !!continuationToken,
                continuationToken: continuationToken,
                timestamp: new Date().toISOString()
            };
            
            context.log(`Batch processing completed. Summary:`, summary);
            
            return {
                status: 200,
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    ...summary,
                    sampleResults: results.slice(0, 10)
                })
            };
            
        } catch (error) {
            context.log(`Fatal error in batch processing: ${error.message}`);
            context.log(error.stack);
            
            return {
                status: 500,
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    status: 'error',
                    message: error.message,
                    processedCount: processedCount,
                    errorCount: errorCount,
                    executionTimeMs: Date.now() - startTime
                })
            };
        }
    }
});

async function processItem(item, processingType, context) {
    switch (processingType) {
        case 'aggregate':
            return aggregateData(item);
        case 'transform':
            return transformData(item);
        case 'enrich':
            return enrichData(item);
        case 'validate':
            return validateData(item);
        default:
            return defaultProcessing(item);
    }
}

function defaultProcessing(item) {
    return {
        id: item.id,
        processed: true,
        processedAt: new Date().toISOString(),
        originalData: item
    };
}

function aggregateData(item) {
    const aggregated = {
        id: item.id,
        count: Array.isArray(item.values) ? item.values.length : 0,
        sum: Array.isArray(item.values) ? item.values.reduce((a, b) => a + (b || 0), 0) : 0,
        processedAt: new Date().toISOString()
    };
    
    if (aggregated.count > 0) {
        aggregated.average = aggregated.sum / aggregated.count;
    }
    
    return aggregated;
}

function transformData(item) {
    const transformed = {
        id: item.id,
        transformedAt: new Date().toISOString()
    };
    
    for (const key in item) {
        if (key !== 'id' && key !== '_rid' && key !== '_self' && key !== '_etag' && key !== '_attachments' && key !== '_ts') {
            if (typeof item[key] === 'string') {
                transformed[key + '_upper'] = item[key].toUpperCase();
                transformed[key + '_length'] = item[key].length;
            } else if (typeof item[key] === 'number') {
                transformed[key + '_squared'] = item[key] * item[key];
            } else {
                transformed[key] = item[key];
            }
        }
    }
    
    return transformed;
}

function enrichData(item) {
    return {
        ...item,
        enriched: true,
        enrichedAt: new Date().toISOString(),
        metadata: {
            processedBy: 'batchDataProcessor',
            version: '1.0',
            enrichmentType: 'standard'
        },
        computed: {
            hash: generateSimpleHash(JSON.stringify(item)),
            size: JSON.stringify(item).length
        }
    };
}

function validateData(item) {
    const validation = {
        id: item.id,
        isValid: true,
        errors: [],
        warnings: [],
        validatedAt: new Date().toISOString()
    };
    
    if (!item.id) {
        validation.isValid = false;
        validation.errors.push('Missing id field');
    }
    
    if (Object.keys(item).length < 2) {
        validation.warnings.push('Item has minimal data');
    }
    
    for (const key in item) {
        if (item[key] === null || item[key] === undefined) {
            validation.warnings.push(`Field ${key} is null or undefined`);
        }
    }
    
    return validation;
}

function generateSimpleHash(str) {
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
        const char = str.charCodeAt(i);
        hash = ((hash << 5) - hash) + char;
        hash = hash & hash;
    }
    return hash.toString(16);
}

